import type { FontWidthMap } from '../../../../core/components/text-ellipsis/chars-font-width-map.js';
import { calculateWidth } from '../../../../core/components/text-ellipsis/truncate-string.js';
import { LABEL_OPTIONS } from '../../../constants.js';
import type { LabelOptions } from '../../../types/canvas.js';

type LabelWidthOptions = {
  nameWidth: number;
  valueWidth: number;
  nameValueWidth: number;
  multiLineWidth: number;
};

export const LINE_SPACING = 2;
export const FONT_SIZE_DIFFERENCE = 1;

/**
 * Returns the labelOption that fits the current node
 * @internal
 * @param height - height of the node.
 * @param width - width of the node.
 * @param fontSize - font size of the label.
 * @param padding - padding around the label
 * @param labelWidth - object containing width for each labelFit scenario,
 */
export const getLabelFit = (
  height: number,
  width: number,
  fontSize: number,
  padding: number,
  labelWidth: LabelWidthOptions,
) => {
  const { nameWidth, nameValueWidth, valueWidth, multiLineWidth } = labelWidth;
  const lineSpacing = 2;
  const paddingSum = 2 * padding;
  const availableWidth = width - paddingSum;
  const minInlineHeight = paddingSum + fontSize;
  const minMultiLineHeight = paddingSum + fontSize * 2 + lineSpacing;

  const fitMultiLine =
    height >= minMultiLineHeight && availableWidth >= multiLineWidth;
  if (fitMultiLine) {
    return LABEL_OPTIONS.Multi;
  }

  const fitInline =
    height >= minInlineHeight && availableWidth >= nameValueWidth;
  if (fitInline) {
    return LABEL_OPTIONS.Inline;
  }

  const fitName = height >= minInlineHeight && availableWidth >= nameWidth;
  if (fitName) {
    return LABEL_OPTIONS.Name;
  }

  const fitEllipsis = height >= minInlineHeight && availableWidth < nameWidth;
  if (fitEllipsis) {
    const fitAtLeastValue =
      height >= minMultiLineHeight && availableWidth >= valueWidth;

    return fitAtLeastValue
      ? LABEL_OPTIONS.EllipsisWithValue
      : LABEL_OPTIONS.Ellipsis;
  }

  return LABEL_OPTIONS.Fallback;
};

/**
 * Returns the center of the node.
 * @internal
 * @param height - height of the node.
 * @param width - width of the node.
 */
export const getRectCenter = (width: number, height: number) => ({
  centerX: width / 2,
  centerY: height / 2,
});

/**
 * Returns the object containing width for each labelFit scenario,
 * using the character width map for estimated measurements.
 * @internal
 * @param nameWidth - pre-calculated name width.
 * @param value - current node value.
 * @param charWidthMap - character width map for width estimation.
 */
export const getLabelWidth = (
  nameWidth: number,
  value: string,
  charWidthMap: FontWidthMap,
) => {
  const valueWidth = calculateWidth(value, charWidthMap);
  const nameValueWidth = nameWidth + calculateWidth(` ${value}`, charWidthMap);
  const multiLineWidth = Math.max(nameWidth, valueWidth);

  return { nameWidth, valueWidth, nameValueWidth, multiLineWidth };
};

/**
 * Returns the array containing the label items for a given node.
 * Depending on the available space labels are shown in 2 lines or in 1 line or with name only.
 * @internal
 * @param labelFit - current labelFit scenario
 * @param name - current node name.
 * @param value - current node value.
 */
export const getAppliedLabels = (
  labelFit: LabelOptions,
  name: string,
  value: string,
) => {
  const labelMap = {
    multi: [name, value],
    inline: [`${name} ${value}`],
    name: [name],
    ellipsis: [name],
    'ellipsis-with-value': [name, value],
    fallback: [],
  };

  return labelMap[labelFit];
};

/**
 * Returns the vertical offset of the labels.
 * @internal
 * @param labels - array of label for the given node.
 * @param labelIndex - current index of the labels array item.
 * @param fontSize - font size value.
 */
export const getOffsetY = (
  labels: string[],
  labelIndex: number,
  fontSize: number,
) => {
  const downOffsetY = Math.round(fontSize / 2) + LINE_SPACING;
  const upOffsetY = -1 * downOffsetY - FONT_SIZE_DIFFERENCE;
  const isMultiLine = labels.length > 1;
  return isMultiLine ? (labelIndex === 0 ? upOffsetY : downOffsetY) : 0;
};
